{
  "plan": {
    "discovery": {
      "method": "Compared dirty working copies against git HEAD to identify what was already implemented vs what needs repair",
      "status": "Core implementation (sidecar-startup-trace.ts, per-phase guards, stderr capture, disk write, safe-mode UI) is 95% complete. Three defects identified in the dirty files."
    },
    "root_causes": [
      {
        "hypothesis": "Parallel lane merge left a duplicate JSX block in safe-mode.tsx",
        "confidence": "high",
        "evidence": [
          "safe-mode.tsx git diff shows the identical {diag?.sidecarFailure && (...)} block added twice at lines ~75 and ~87",
          "The two blocks have identical class names, identical field access, and identical structure",
          "Both blocks test `diag?.sidecarFailure` — only one fires, but both are rendered in the source"
        ]
      },
      {
        "hypothesis": "writePhase() calls were copy-pasted between phases without updating the phase string",
        "confidence": "high",
        "evidence": [
          "Phase 2 (loopback-proxy) at sidecar.ts:142 uses writePhase('sidecar.env.prepare', ...) — same as Phase 1",
          "Phase 3 (system-certs) at :153 also uses 'sidecar.env.prepare'",
          "Phase 4 (env-proxy) at :164 also uses 'sidecar.env.prepare'",
          "Phase 6 (log-init) at :187 uses 'sidecar.config.load' — same as Phase 5",
          "sidecar-startup-trace.ts defines StartupPhase with distinct phase names but they are not used"
        ]
      },
      {
        "hypothesis": "errorCode field written to sidecar-boot-failure.json has no corresponding type declaration",
        "confidence": "high",
        "evidence": [
          "sidecar.ts:90 writes JSON.stringify({ errorCode, phase, port, ... })",
          "types.ts SidecarStartupFailure (lines 20-32) has no errorCode field",
          "index.ts assigns JSON.parse() result to sidecarFailure: SidecarStartupFailure | null"
        ]
      }
    ],
    "fixes": [
      {
        "id": "fix-A",
        "description": "Remove duplicate sidecarFailure JSX block from safe-mode.tsx",
        "files": ["packages/desktop/src/renderer/safe-mode.tsx"],
        "before": "Lines 86-103: duplicate {diag?.sidecarFailure && (<div class=\"flex flex-col gap-2 w-full max-w-md rounded-lg border border-warning-base bg-warning-weak p-4 mt-2\">...)} block",
        "after": "Delete the duplicate block (lines 86-103), keeping only the first occurrence (lines 75-84)",
        "impact": {
          "affected_files": ["packages/desktop/src/renderer/safe-mode.tsx"],
          "tests_to_run": ["bun typecheck from packages/desktop"]
        },
        "risks": [
          "If the wrong copy is deleted, the UI will still render correctly since both are identical — just ensure the remaining copy is properly positioned between error details and action cards"
        ],
        "validation": [
          "bun typecheck from packages/desktop",
          "Visual: safe-mode.tsx should have exactly ONE {diag?.sidecarFailure && (...)} block",
          "Verify both blocks are byte-identical before deleting — they differ only in line position"
        ]
      },
      {
        "id": "fix-B",
        "description": "Fix writePhase() phase names for phases 2-6 in sidecar.ts",
        "files": ["packages/desktop/src/main/sidecar.ts"],
        "before": {
          "phase2_loopback": "writePhase(\"sidecar.env.prepare\", \"started\")\n    ensureLoopbackNoProxy()\n    lastSuccessfulPhase = \"loopback-proxy\"\n    writePhase(\"sidecar.env.prepare\", \"completed\")",
          "phase3_certs": "writePhase(\"sidecar.env.prepare\", \"started\")\n    useSystemCertificates()\n    lastSuccessfulPhase = \"system-certs\"\n    writePhase(\"sidecar.env.prepare\", \"completed\")",
          "phase4_proxy": "writePhase(\"sidecar.env.prepare\", \"started\")\n    useEnvProxy()\n    lastSuccessfulPhase = \"env-proxy\"\n    writePhase(\"sidecar.env.prepare\", \"completed\")",
          "phase5_import": "writePhase(\"sidecar.config.load\", \"started\")\n    const mod = await import(...)\n    ...\n    writePhase(\"sidecar.config.load\", \"completed\")",
          "phase6_log": "writePhase(\"sidecar.config.load\", \"started\")\n    await Log.init(...)\n    lastSuccessfulPhase = \"log-init\"\n    writePhase(\"sidecar.config.load\", \"completed\")"
        },
        "after": {
          "phase2_loopback": "writePhase(\"sidecar.proxy.loopback\", \"started\")\n    ensureLoopbackNoProxy()\n    lastSuccessfulPhase = \"loopback-proxy\"\n    writePhase(\"sidecar.proxy.loopback\", \"completed\")",
          "phase3_certs": "writePhase(\"sidecar.certs.system\", \"started\")\n    useSystemCertificates()\n    lastSuccessfulPhase = \"system-certs\"\n    writePhase(\"sidecar.certs.system\", \"completed\")",
          "phase4_proxy": "writePhase(\"sidecar.proxy.env\", \"started\")\n    useEnvProxy()\n    lastSuccessfulPhase = \"env-proxy\"\n    writePhase(\"sidecar.proxy.env\", \"completed\")",
          "phase5_import": "writePhase(\"sidecar.config.load\", \"started\")\n    const mod = await import(...)\n    ...\n    writePhase(\"sidecar.config.load\", \"completed\")",
          "phase6_log": "writePhase(\"sidecar.log.init\", \"started\")\n    await Log.init(...)\n    lastSuccessfulPhase = \"log-init\"\n    writePhase(\"sidecar.log.init\", \"completed\")"
        },
        "impact": {
          "affected_files": ["packages/desktop/src/main/sidecar.ts", "packages/desktop/src/main/sidecar-startup-trace.ts (need to add new phase strings to StartupPhase type)"],
          "tests_to_run": ["bun test test/sidecar-startup-truth.test.ts", "bun typecheck from packages/desktop"]
        },
        "risks": [
          "Adding new phase strings (sidecar.proxy.loopback, sidecar.certs.system, sidecar.proxy.env, sidecar.log.init) to StartupPhase type in sidecar-startup-trace.ts is required — otherwise tsgo fails",
          "The new phase names must be added to the StartupPhase union type in sidecar-startup-trace.ts:37-53"
        ],
        "validation": [
          "bun typecheck from packages/desktop — must pass",
          "grep writePhase sidecar.ts | sort | uniq to verify each phase uses a distinct name",
          "Verify StartupPhase type in sidecar-startup-trace.ts includes all new phases"
        ]
      },
      {
        "id": "fix-C",
        "description": "Add errorCode field to SidecarStartupFailure type",
        "files": ["packages/desktop/src/preload/types.ts"],
        "before": "export type SidecarStartupFailure = {\n  phase: string\n  port: number | null\n  hostname: string | null\n  lastSuccessfulPhase: string\n  errorMessage: string\n  errorStack: string\n  exitCode: number\n  stderrTail: string\n  timestamp: string\n  platform: string\n  nodeVersion: string\n}",
        "after": "export type SidecarStartupFailure = {\n  errorCode?: string\n  phase: string\n  port: number | null\n  hostname: string | null\n  lastSuccessfulPhase: string\n  errorMessage: string\n  errorStack: string\n  exitCode: number\n  stderrTail: string\n  timestamp: string\n  platform: string\n  nodeVersion: string\n}",
        "impact": {
          "affected_files": ["packages/desktop/src/preload/types.ts"],
          "tests_to_run": ["bun typecheck from packages/desktop"]
        },
        "risks": [
          "Minimal — adding an optional field is backward-compatible. TypeScript won't complain about missing errorCode when reading older files.",
          "If errorCode is used in safe-mode.tsx UI, need a follow-up UI change to display it."
        ],
        "validation": [
          "bun typecheck from packages/desktop",
          "SidecarStartupFailure type in types.ts now includes errorCode?: string"
        ]
      }
    ],
    "apply_order": ["fix-A", "fix-B", "fix-C"],
    "rollback_plan": "git checkout -- packages/desktop/src/renderer/safe-mode.tsx packages/desktop/src/main/sidecar.ts packages/desktop/src/main/sidecar-startup-trace.ts packages/desktop/src/preload/types.ts"
  },
  "already_complete": {
    "files_done": [
      "packages/desktop/src/main/sidecar-startup-trace.ts — fully implemented (untracked, new file)",
      "packages/desktop/src/main/index.ts — readFileSync import added, getSafeModeDiagnostics reads sidecar-boot-failure.json",
      "packages/desktop/src/main/sidecar.ts — per-phase guards, stderr capture, fail() writes to disk then IPC (needs fix-B)",
      "packages/desktop/src/preload/types.ts — SidecarStartupFailure type and SafeModeDiagnostics.sidecarFailure added (needs fix-C)",
      "packages/desktop/src/renderer/safe-mode.tsx — sidecarFailure UI block added (needs fix-A)"
    ],
    "tests_existing": [
      "packages/desktop/test/sidecar-startup-truth.test.ts — 9 regression tests for classifyError()"
    ]
  }
}
